// The det_set ensures is `LHS ==> det_set_equal(...)`. At the top of the
// body, `post1_self_.valid()` and `post2_self_.valid()` are *not* hypotheses
// -- they sit on the LHS of the implication we have to prove. The previous
// attempt called `post1_self_.valid_implies_complete()` directly and Verus
// rejected it because its precondition `self.valid()` was unknown. We fix
// that by wrapping the body in `if <LHS> { ... }`, which makes every LHS
// conjunct (the two `.valid()`s and the four foralls) available as
// hypotheses inside the branch; in the else branch the implication is
// vacuous, so the ensures is established by case analysis.
if post1_self_.valid()
    && post2_self_.valid()
    && (forall |ki:KeyIterator<K>| #[trigger] KeyIterator::between(*lo, ki, *hi) ==> post1_self_@[*ki.get()] == dst@)
    && (forall |ki:KeyIterator<K>| !ki.is_end_spec() && !(#[trigger] KeyIterator::between(*lo, ki, *hi)) ==> post1_self_@[*ki.get()] == pre_self_@[*ki.get()])
    && (forall |ki:KeyIterator<K>| #[trigger] KeyIterator::between(*lo, ki, *hi) ==> post2_self_@[*ki.get()] == dst@)
    && (forall |ki:KeyIterator<K>| !ki.is_end_spec() && !(#[trigger] KeyIterator::between(*lo, ki, *hi)) ==> post2_self_@[*ki.get()] == pre_self_@[*ki.get()])
{
    // Inside this branch all three states are valid, so their domains are
    // the full set of K. `pre_self_.valid()` is in the requires of det_set,
    // and the two post `.valid()`s come from the LHS we just split on.
    pre_self_.valid_implies_complete();
    post1_self_.valid_implies_complete();
    post2_self_.valid_implies_complete();
    assert(post1_self_@.dom() =~= post2_self_@.dom());

    // Bridge the iterator-quantified ensures to a K-quantified pointwise
    // equality. For each k, ki = KeyIterator::new_spec(k) is non-end and
    // *ki.get_spec() == k. Mentioning `KeyIterator::between(*lo, ki, *hi)`
    // in the if-condition supplies the ground trigger that fires both
    // ensures-foralls on our specific ki.
    assert forall |k: K| #[trigger] post1_self_@.dom().contains(k)
        implies post1_self_@[k] == post2_self_@[k] by
    {
        let ki = KeyIterator::<K>::new_spec(k);
        assert(!ki.is_end_spec());
        assert(*ki.get_spec() == k);
        if KeyIterator::between(*lo, ki, *hi) {
            // The `between` branch of both ensures-foralls fires:
            assert(post1_self_@[*ki.get_spec()] == dst@);
            assert(post2_self_@[*ki.get_spec()] == dst@);
            assert(post1_self_@[k] == dst@);
            assert(post2_self_@[k] == dst@);
        } else {
            // The `!is_end_spec && !between` branch fires; pre_self_'s
            // domain is full so the Map::index recommendation is satisfied.
            assert(post1_self_@[*ki.get_spec()] == pre_self_@[*ki.get_spec()]);
            assert(post2_self_@[*ki.get_spec()] == pre_self_@[*ki.get_spec()]);
            assert(post1_self_@[k] == pre_self_@[k]);
            assert(post2_self_@[k] == pre_self_@[k]);
        }
    };

    // Domains coincide (both full) and values agree pointwise, so the maps
    // are extensionally equal, and r1 == r2 trivially (both are `()`).
    assert(post1_self_@ =~= post2_self_@);
    assert(r1 == r2);
    assert(det_set_equal(r1, r2, post1_self_, post2_self_));
}
